-- Rate limit check function
CREATE OR REPLACE FUNCTION public.check_rate_limit(
  p_key text,
  p_window_minutes integer DEFAULT 60,
  p_max_requests integer DEFAULT 5
)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
DECLARE
  v_count integer;
  v_window_start timestamp with time zone;
BEGIN
  v_window_start := now() - (p_window_minutes || ' minutes')::interval;

  -- Count requests in window
  SELECT COALESCE(SUM(request_count), 0) INTO v_count
  FROM public.rate_limits
  WHERE key = p_key AND window_start > v_window_start;

  -- If over limit, return false
  IF v_count >= p_max_requests THEN
    RETURN false;
  END IF;

  -- Record this request
  INSERT INTO public.rate_limits (key, window_start, request_count)
  VALUES (p_key, now(), 1);

  -- Periodically cleanup (1% chance per request)
  IF random() < 0.01 THEN
    PERFORM public.cleanup_old_rate_limits();
  END IF;

  RETURN true;
END;
$$

-- Create function to auto-assign free subscription
CREATE OR REPLACE FUNCTION public.handle_new_profile_subscription()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.subscriptions (profile_id, status, plan_type, starts_at, expires_at)
  VALUES (NEW.id, 'active', 'free', NOW(), NOW() + INTERVAL '10 years');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER
